#include<bits/stdc++.h>
using namespace std;
struct node
{
    int a,b;
}f[500010];
int n,q,nxt[500010][21];
int main()
{
    stack<int> s;
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&f[i].a);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&f[i].b);
    }
    for(int i=1;i<=n;i++)
    {
        while(!s.empty()&&(f[s.top()].a==f[i].a||f[s.top()].b<=f[i].b))
        {
            nxt[s.top()][0]=i;
            s.pop();
        }
        s.push(i);
    }
    for(int i=1;i<=20;i++)
    {
        for(int j=1;j<=n;j++)
        {
            nxt[j][i]=nxt[nxt[j][i-1]][i-1];
        }
    }
    while(q--)
    {
        int l,r,ans=1;
        scanf("%d%d",&l,&r);
        for(int i=20;i>=0;i--)
        {
            if(nxt[l][i]&&nxt[l][i]<=r)
            {
                ans+=(1<<i);
                l=nxt[l][i];
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
